#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int a, b, x, y;
        scanf("%d %d %d %d", &a, &b, &x, &y);
        if (x == 0 || y == 0 || x + b == a || y + b == a) {
            printf("yes\n");
        } else {
            printf("no\n");
        }
    }
    return 0;
}

