public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int a = sc.nextInt();
            int b = sc.nextInt();
            int x = sc.nextInt();
            int y = sc.nextInt();
            if (x == 0 || y == 0 || x + b == a || y + b == a) {
                System.out.println("yes");
            } else {
                System.out.println("no");
            }
        }
    }
}

